function svgToDataUri(svg, color) {
  const colored = svg.replace(/"C"/g, '"' + color + '"')
  const encoded = encodeURIComponent(colored)
  return 'data:image/svg+xml,' + encoded
}

// Old uni-icons name → IconPark name aliases
const aliases = {
  'notification-filled': 'horn',
  'plusempty': 'plus',
  'closeempty': 'close',
  'checkmarkempty': 'checkCorrect',
  'clock-filled': 'clock',
  'locked-filled': 'lock',
  'location-filled': 'location',
  'flag-filled': 'flag',
  'image-filled': 'picture',
  'checkbox-filled': 'checkCorrect',
  'star-filled': 'star',
  'info-filled': 'info',
  'medal-filled': 'medal',
  'wallet-filled': 'wallet',
  'navigate-filled': 'navigation',
  'chat-filled': 'chat',
  'shop': 'shoppingBag',
  'express': 'expressDelivery',
  'withdraw': 'bankCard',
  'fire': 'snacks',
  'bars': 'filter',
  'notification': 'horn',
  'sound': 'horn',
  'compose': 'compose',
  'trash': 'delete',
  'phone': 'phoneCall',
  'medal-filled': 'idCard',
  'medal': 'permissions',
  'copy': 'copyIcon',
}

const svgUri = computed(() => {
  const lookup = aliases[props.name] || props.name
  const svg = icons[lookup]
  if (!svg) {
    console.warn('[iconpark-icon] Unknown icon:', props.name)
    return ''
  }
  const c = props.color || '#1C1B1A'
  return svgToDataUri(svg, c)
})
